var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"흐음……. 이 끈적거리고 불쾌한 공기…….","JPN":"ふーん……このねっとりした不快な空気……","ENG":"Hmm... This suffocating and unpleasant air...","TWN":"嗯……這黏膩不愉快的空氣……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"확실히 맥크레디 영지는 살기 좋은 곳이 아니네.","JPN":"確かにマクレディー領地は住みやすいところではないわね。","ENG":"Guess the MacCready Estate is not such a pleasant place to live.","TWN":"麥克蕾蒂領地確實不適合居住。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"며칠만 지내도 머리가 이상해지겠어.","JPN":"何日か過ごしただけで頭がおかしくなりそう。","ENG":"Just staying here for a couple of days might make anyone go nuts.","TWN":"只是生活幾天，腦袋就該變得奇怪了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"역시 주민들의 모습은 보이지 않는군요.","JPN":"やはり住民の姿は見当たりませんわ。","ENG":"I do not see any signs of the residents.","TWN":"果然看不到居民們的影子呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"처음 돌아왔을 때보다 더 삭막해졌어요.","JPN":"最初に戻ってきた時よりもの寂しくなっています。","ENG":"It has become more desolate than when I had first arrived.","TWN":"比剛回來時更淒涼了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"에이. 무슨 소리야, 레지나.","JPN":"え～？　何言ってるんだよ、レジーナ。","ENG":"C'mon. What are you talking about, Regina?","TWN":"哎呀，你說什麼呢，蕾佳娜。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"우리 오기만 목이 빠져라 기다리던 사람들이 있는 것 같은데.","JPN":"アタシたちのことを首を長くして待ってた人たちがいるみたいだけど。","ENG":"I think I see some who are eagerly awaiting our return.","TWN":"好像有人正望眼欲穿地等著我們回來呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하, 학회원 분들이에요……","JPN":"が、学会員の方々です……","ENG":"I-it's the Society members...","TWN":"是…是學會成員……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 뒤로 숨으세요. 우리 중 가장 노리기 쉬운 사람은 당신입니다.","JPN":"私の後ろに隠れてください。私たちの中でもっとも狙われやすいのはあなたです。","ENG":"Hide behind me. You are the easiest to target out of all of us.","TWN":"躲到我後面，我們當中最容易被盯上的人就是你。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"오해하지 마십시오. 법학부는 불필요한 무력을 사용하진 않습니다.","JPN":"誤解しないでください。法学部は不要な武力は使いません。","ENG":"Don't be alarmed. The Law Department doesn't use unnecessary force.","TWN":"請不要誤會。法學院不會使用不必要的武力。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_NPC_ESPR2_NULL","text":{"KOREA":"집행에 순응한다면 충돌도 없어요.","JPN":"執行に応じれば衝突は避けられます。","ENG":"If you surrender, there will be no bloodshed.","TWN":"只要你們配合，也不會有衝突。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"SWORD_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저, 저건……","JPN":"あ、あれは……","ENG":"Th-that's...","TWN":"那…那是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"법학부장.","JPN":"法学部長。","ENG":"The Dean of Law.","TWN":"法學院院長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이런, 큰일났네.","JPN":"まあ、大変。","ENG":"Yikes. We're in trouble now.","TWN":"哎呀，糟了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"지금이라도 도망쳐야 하지 않을까요, 부학회장님.","JPN":"今からでも逃げた方がいいのではないでしょうか、副学会長。","ENG":"Don't you think we should run, Ms. Vice President?","TWN":"現在是不是應該逃跑，副學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어째서죠? 여기서 물러서면 다음이 없어요.","JPN":"どうしてですか？　ここで引き下がれば次はありません。","ENG":"Why would we? There is nowhere to run from here.","TWN":"為什麼呢？如果就此退下，就再沒有下次了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};